            }
        }

        // Check if the inserted character is 'L', 'C', or 'T'
        if (insertChar === 'L') {
            return Math.max(tCount, preTCount, midTCount);
        } else if (insertChar === 'C') {
            return Math.max(tCount, preTCount, midTCount);
        } else if (insertChar === 'T') {
            return Math.max(tCount, preTCount, midTCount);
        } else {
            return tCount;
        }
    };

    let maxCount = 0;
    maxCount = Math.max(maxCount, findLCt('L'));
    maxCount = Math.max(maxCount, findLCt('C'));
    maxCount = Math.max(maxCount, findLCt('T'));

    return maxCount;
}
